WITH MostRecentQualityTest AS (
    SELECT 
        f.flour_id,
        f.flour_name,
        ft.test_id,
        ft.test_result,
        ft.test_date,
        ROW_NUMBER() OVER (PARTITION BY f.flour_id ORDER BY ft.test_date DESC) AS test_rank
    FROM 
        flours f
    INNER JOIN 
        flour_quality_tests ft ON f.flour_id = ft.flour_id
)
SELECT 
    mrt.flour_name,
    mrt.test_result,
    mrt.test_date,
    fn.german_value,
    fn.french_value,
    fn.italian_value,
    fn.netherlands_value,
    fn.fiber_content,
    fn.fat_content,
    fn.carbohydrate_content,
    fn.calories,
    fn.vitamin_content,
    fn.mineral_content
FROM 
    MostRecentQualityTest mrt
INNER JOIN 
    flour_nutrition fn ON mrt.flour_id = fn.flour_id
WHERE 
    mrt.test_rank = 1
ORDER BY 
    mrt.test_date DESC;

