WITH LatestQualityTests AS (
    SELECT
        ft.flour_id,
        ft.test_result,
        ft.test_type,
        ROW_NUMBER() OVER (PARTITION BY ft.flour_id ORDER BY ft.test_date DESC) AS latest_test_rank
    FROM
        flour_quality_tests ft
),
FlourNutrition AS (
    SELECT
        f.flour_id,
        f.flour_name,
        fn.fiber_content,
        fn.fat_content,
        fn.carbohydrate_content,
        fn.calories,
        fn.vitamin_content,
        fn.mineral_content
    FROM
        flours f
    JOIN
        flour_nutrition fn ON f.flour_id = fn.flour_id
)
SELECT
    fn.flour_name AS Flour,
    fn.fiber_content AS FiberContent,
    fn.fat_content AS FatContent,
    fn.carbohydrate_content AS CarbohydrateContent,
    fn.calories AS Calories,
    fn.vitamin_content AS VitaminContent,
    fn.mineral_content AS MineralContent,
    lqt.test_result AS LatestTestResult,
    lqt.test_type AS LatestTestType
FROM
    FlourNutrition fn
LEFT JOIN
    LatestQualityTests lqt ON fn.flour_id = lqt.flour_id
WHERE
    lqt.latest_test_rank = 1
ORDER BY
    fn.flour_name;

external_knowledge:
- `flour_id` is a unique identifier for each type of flour in the database;
- The nutritional values are provided in multiple units (German, French, Italian, Dutch) to cater to different regions;
- Quality tests are conducted to ensure the flour meets certain standards before usage;
- Usage records track the quantity of flour used, the date it was used, and the item produced.

