  fn.mineral_content,
  ft.test_result,
  ft.test_type,
  ft.test_method,
  fur.quantity_used,
  fur.usage_date,
  fur.produced_item
FROM 
  flours f
LEFT JOIN 
  flour_nutrition fn ON f.flour_id = fn.flour_id
LEFT JOIN 
  flour_quality_tests ft ON f.flour_id = ft.flour_id
LEFT JOIN 
  flour_usage_records fur ON f.flour_id = fur.flour_id
WHERE 
  f.flour_id = 0;

